def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        complex_factor = 1.0
        for m in range(1, 6):
            for n in range(1, 6):
                val = (m * n) ** 0.8
                if (cap + m - n) % 4 == 0:
                    val *= 1.05
                elif (item * m + n) % 5 == 0:
                    val *= 0.95
                if ratio > 0.5 and val < item:
                    score += val * np.sin(ratio * m * n)
                else:
                    score -= val * np.cos(ratio + m / (n + 0.1))
                if m == 3 and n == 3:
                    for p in range(1, 4):
                        diff = cap - item * p
                        if diff > 0:
                            if diff % 3 == 0:
                                score += np.cbrt(diff) / (p + 1)
                            else:
                                score -= np.log1p(abs(diff)) * 0.5 / (p + 2)
                        else:
                            penalty = (abs(diff)) ** 1.3 / (p + 3)
                            if ratio < 0.3:
                                score -= penalty * 1.1
                            else:
                                score -= penalty * 0.9
            if ratio < 0.4:
                complex_factor *= (1 + 0.02 * m)
            else:
                complex_factor *= (0.98 - 0.01 * m)
        score *= complex_factor
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            penalty_factor = np.log1p(cap + item) ** (0.5 + ratio)
            priorities[i] = -score * penalty_factor
            if cap % 7 == 0:
                priorities[i] *= 1.1
            if (item + cap) % 11 == 0:
                priorities[i] *= 0.88
        else:
            denom = np.sqrt(cap + 1) if cap > item * 2 else (cap + 5)
            priorities[i] = -score / denom
            if ratio > 0.85:
                priorities[i] *= 1.15
            elif ratio < 0.15:
                priorities[i] *= 0.75
        if ratio > 1.0:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.6
        if i % 2 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 0.95
    return priorities
